import pandas as pd


def clean_text(text):
    """Lowercase, strip, and collapse whitespace. Returns '' for null/empty."""
    if not isinstance(text, str):
        return ""
    return " ".join(text.lower().strip().split())


def load_and_clean(path):
    df = pd.read_csv(path)
    df["message"] = df["message"].map(clean_text)
    df = df[df["message"].str.len() > 0].reset_index(drop=True)
    return df

from clean import clean_text


def test_lowercases_and_strips():
    assert clean_text("  FREE Prize!!  ") == "free prize!!"


def test_collapses_whitespace():
    assert clean_text("win\t a   prize") == "win a prize"


def test_handles_none_and_empty():
    assert clean_text(None) == ""
    assert clean_text("   ") == ""
